def ConnectionPool(max_size=5):
    # Maintain a global-like counter across pool instances
    if not hasattr(ConnectionPool, "_counter"):
        ConnectionPool._counter = 0
        ConnectionPool._counter_lock = threading.Lock()

    class _Conn:
        def __init__(self):
            with ConnectionPool._counter_lock:
                ConnectionPool._counter += 1
                self.id = ConnectionPool._counter
            self.closed = False

        def execute(self, query):
            if self.closed:
                raise RuntimeError('Connection is closed')
            return f'Result of {query} on conn {self.id}'

        def close(self):
            self.closed = True

    class _Pool:
        def __init__(self, max_size_inner):
            self.max_size = max_size_inner
            self._pool = deque()
            self._in_use = set()
            self._lock = threading.Lock()
            self._current_conn = None
            for _ in range(max_size_inner):
                self._pool.append(_Conn())

        def acquire(self):
            with self._lock:
                if not self._pool:
                    raise RuntimeError('No connections available')
                conn = self._pool.popleft()
                self._in_use.add(conn)
                return conn

        def release(self, conn):
            with self._lock:
                if conn in self._in_use:
                    self._in_use.remove(conn)
                    self._pool.append(conn)

        def __enter__(self):
            self._current_conn = self.acquire()
            return self._current_conn

        def __exit__(self, exc_type, exc_val, exc_tb):
            conn = getattr(self, '_current_conn', None)
            try:
                if conn is not None:
                    try:
                        self.release(conn)
                    except Exception:
                        # Never let release errors mask the original exception
                        pass
            finally:
                self._current_conn = None
            # Do not suppress exceptions
            return False

        @property
        def available(self):
            with self._lock:
                return len(self._pool)

        @property
        def in_use_count(self):
            with self._lock:
                return len(self._in_use)

    return _Pool(max_size)

